            await ShipmentService.CreateShipmentAsync(newShipment);
            showNewForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            createError = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            creating = false;
        }
    }

    private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus) && newStatus != shipment.Status)
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
            {
                shipment.ActualDelivery = DateTime.UtcNow;
            }
        }
    }

