using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = new List<string>();
        if (!string.IsNullOrEmpty(statusFilter)) query.Add($"status={Uri.EscapeDataString(statusFilter)}");
        if (!string.IsNullOrEmpty(searchTerm)) query.Add($"search={Uri.EscapeDataString(searchTerm)}");
        var url = query.Count > 0 ? $"/api/shipments?{string.Join("&", query)}" : "/api/shipments";
        return await httpClient.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await httpClient.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var response = await httpClient.GetAsync($"/api/shipments/{id}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await httpClient.PostAsJsonAsync("/api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var response = await httpClient.PutAsJsonAsync($"/api/shipments/{id}/status", new UpdateShipmentStatusRequest { NewStatus = newStatus });
        response.EnsureSuccessStatusCode();
    }
}
```

