@page "/track/{TrackingNumber}"

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

@inject IShipmentService ShipmentService
@inject NavigationManager Navigation

<PageTitle>Track Shipment@(TrackingNumber is not null ? $" - {TrackingNumber}" : "")</PageTitle>

<div class="container py-4">
    <h2>Track Shipment</h2>

    <div class="input-group mb-4" style="max-width: 500px;">
        <input type="text" class="form-control" placeholder="Enter tracking number..."
               @bind="searchTrackingNumber" @bind:event="oninput"
               @onkeydown="HandleSearchKeyDown" />
        <button class="btn btn-primary" @onclick="SearchShipment">Search</button>
    </div>

    @if (loading)
    {
        <div class="d-flex align-items-center">
            <div class="spinner-border spinner-border-sm me-2" role="status"></div>
            <span>Looking up shipment...</span>
        </div>
    }
    else if (TrackingNumber is null)
    {
        <div class="alert alert-info">Enter a tracking number above to look up a shipment.</div>
    }
    else if (shipment is null)
    {
        <div class="alert alert-warning">
            <strong>Shipment not found.</strong> No shipment matches tracking number <code>@TrackingNumber</code>.
            Please check the number and try again.
        </div>
    }
    else
    {
        <div class="card shadow-sm">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">@shipment.TrackingNumber</h5>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row g-3">
                    <div class="col-md-6">
                        <strong>Recipient:</strong> @shipment.RecipientName
                    </div>
                    <div class="col-md-6">
                        <strong>Weight:</strong> @shipment.WeightKg.ToString("F1") kg
                    </div>
                    <div class="col-md-6">
                        <strong>Origin:</strong> @shipment.Origin
                    </div>
                    <div class="col-md-6">
                        <strong>Destination:</strong> @shipment.Destination
                    </div>
                    <div class="col-md-6">
                        <strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")
                    </div>
                    <div class="col-md-6">
                        <strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")
                    </div>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <div class="col-md-6">
                            <strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy HH:mm")
                        </div>
                    }
                    @if (!string.IsNullOrEmpty(shipment.Description))
                    {
                        <div class="col-12">
                            <strong>Description:</strong> @shipment.Description
                        </div>
                    }
                </div>

                <hr />

                <h6>Shipment Progress</h6>
                <div class="progress mb-2" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public string? TrackingNumber { get; set; }

    private ShipmentDto? shipment;
    private bool loading;
    private string searchTrackingNumber = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await LoadShipment();
        }
        else
        {
            loading = false;
        }
    }

    private async Task LoadShipment()
    {
        loading = true;
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(TrackingNumber!);
        loading = false;
    }

    private void SearchShipment()
    {
        if (!string.IsNullOrWhiteSpace(searchTrackingNumber))
        {
            Navigation.NavigateTo($"track/{Uri.EscapeDataString(searchTrackingNumber.Trim())}");
        }
    }

    private void HandleSearchKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") SearchShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

@page "/dispatcher"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<div class="container-fluid py-4">
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h2>Dispatcher Dashboard</h2>
        <button class="btn btn-success" @onclick="ToggleNewShipmentForm">
            @(showNewForm ? "Cancel" : "+ New Shipment")
        </button>
    </div>

    @if (showNewForm)
    {
        <div class="card mb-4 shadow-sm">
            <div class="card-header"><h5 class="mb-0">Create New Shipment</h5></div>
            <div class="card-body">
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <input type="text" class="form-control" @bind="newShipment.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <input type="text" class="form-control" @bind="newShipment.Destination" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recipient Name</label>
                        <input type="text" class="form-control" @bind="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Weight (kg)</label>
                        <input type="number" class="form-control" step="0.1" @bind="newShipment.WeightKg" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Delivery</label>
                        <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-12">
                        <label class="form-label">Description</label>
                        <input type="text" class="form-control" @bind="newShipment.Description" />
                    </div>
                    <div class="col-12">
                        <button class="btn btn-primary" @onclick="CreateShipment" disabled="@creating">
                            @(creating ? "Creating..." : "Create Shipment")
                        </button>
                    </div>
                </div>
                @if (!string.IsNullOrEmpty(createError))
                {
                    <div class="alert alert-danger mt-3">@createError</div>
                }
            </div>
        </div>
    }

    <div class="row g-3 mb-4">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Search by tracking #, destination, recipient..."
                   @bind="searchTerm" @bind:event="oninput" @onkeydown="HandleSearchKeyDown" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                @foreach (var s in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@s">@s</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-primary w-100" @onclick="LoadShipments">Apply Filters</button>
        </div>
    </div>

    @if (loading)
    {
        <div class="d-flex align-items-center">
            <div class="spinner-border spinner-border-sm me-2" role="status"></div>
            <span>Loading shipments...</span>
        </div>
    }
    else if (shipments.Count == 0)
    {
        <div class="alert alert-info">No shipments found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Recipient</th>
                        <th>Status</th>
                        <th>Shipped</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var s in shipments)
                    {
                        <tr>
                            <td><code>@s.TrackingNumber</code></td>
                            <td>@s.Origin</td>
                            <td>@s.Destination</td>
                            <td>@s.RecipientName</td>
                            <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                            <td>@s.ShippedDate.ToString("MMM dd")</td>
                            <td>@s.EstimatedDelivery.ToString("MMM dd")</td>
                            <td>
                                @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                                {
                                    <div class="btn-group btn-group-sm">
                                        <select class="form-select form-select-sm" style="width: auto;"
                                                @onchange="(e) => OnStatusChanged(s, e)">
                                            @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                            {
                                                <option value="@st" selected="@(st == s.Status)">@st</option>
                                            }
                                        </select>
                                    </div>
                                }
                                else
                                {
                                    <span class="text-muted">—</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    private List<ShipmentDto> shipments = [];
    private bool loading = true;
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;

    private bool showNewForm;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
    private bool creating;
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
        loading = false;
    }

    private void HandleSearchKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            _ = LoadShipments();
        }
    }

    private void ToggleNewShipmentForm()
    {
        showNewForm = !showNewForm;
        if (showNewForm)
        {
            newShipment = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
            createError = null;
        }
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.Origin) ||
            string.IsNullOrWhiteSpace(newShipment.Destination) ||
            string.IsNullOrWhiteSpace(newShipment.RecipientName))
        {
            createError = "Origin, Destination, and Recipient Name are required.";
            return;
        }

        creating = true;
        createError = null;
        try
        {
            await ShipmentService.CreateShipmentAsync(newShipment);
            showNewForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            createError = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            creating = false;
        }
    }

    private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus) && newStatus != shipment.Status)
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
            {
                shipment.ActualDelivery = DateTime.UtcNow;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

