                                {
                                    <div class="btn-group btn-group-sm">
                                        <select class="form-select form-select-sm" style="width: auto;"
                                                @onchange="(e) => OnStatusChanged(s, e)">
                                            @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                            {
                                                <option value="@st" selected="@(st == s.Status)">@st</option>
                                            }
                                        </select>
                                    </div>
                                }
                                else
                                {
                                    <span class="text-muted">—</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    private List<ShipmentDto> shipments = [];
    private bool loading = true;
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;

    private bool showNewForm;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
    private bool creating;
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
        loading = false;
    }

    private void HandleSearchKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            _ = LoadShipments();
        }
    }

    private void ToggleNewShipmentForm()
    {
        showNewForm = !showNewForm;
        if (showNewForm)
        {
            newShipment = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
            createError = null;
        }
    }

    private async Task CreateShipment()
    {
        if (string.IsNullOrWhiteSpace(newShipment.Origin) ||
            string.IsNullOrWhiteSpace(newShipment.Destination) ||
            string.IsNullOrWhiteSpace(newShipment.RecipientName))
        {
            createError = "Origin, Destination, and Recipient Name are required.";
            return;
        }

        creating = true;
        createError = null;
        try
        {
            await ShipmentService.CreateShipmentAsync(newShipment);
            showNewForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            createError = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            creating = false;
        }
    }

    private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus) && newStatus != shipment.Status)
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
            {
                shipment.ActualDelivery = DateTime.UtcNow;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

