         options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
     })
     .AddEntityFrameworkStores<ApplicationDbContext>()
     .AddSignInManager()
     .AddDefaultTokenProviders();

 builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();

 builder.Services.AddScoped<IShipmentService, ServerShipmentService>();

 var app = builder.Build();

 // Seed sample shipments
 using (var scope = app.Services.CreateScope())
 {
     var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
     db.Database.Migrate();
     if (!db.Shipments.Any())
     {
         db.Shipments.AddRange(
             new Shipment { TrackingNumber = "SHP-20260501-10001", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = (int)ShipmentStatus.InTransit, ShippedDate = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(2), RecipientName = "Alice Johnson", Description = "Electronics - Laptop", WeightKg = 2.5 },
             new Shipment { TrackingNumber = "SHP-20260501-10002", Origin = "Chicago, IL", Destination = "Miami, FL", Status = (int)ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow.AddDays(0), RecipientName = "Bob Smith", Description = "Furniture - Office Chair", WeightKg = 15.0 },
             new Shipment { TrackingNumber = "SHP-20260501-10003", Origin = "Seattle, WA", Destination = "Denver, CO", Status = (int)ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(5), RecipientName = "Carol Davis", Description = "Books - Textbooks", WeightKg = 4.2 },
             new Shipment { TrackingNumber = "SHP-20260501-10004", Origin = "Boston, MA", Destination = "Houston, TX", Status = (int)ShipmentStatus.Delivered, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow.AddDays(-2), ActualDelivery = DateTime.UtcNow.AddDays(-2), RecipientName = "David Wilson", Description = "Clothing - Winter Coats", WeightKg = 3.0 },
             new Shipment { TrackingNumber = "SHP-20260501-10005", Origin = "San Francisco, CA", Destination = "Portland, OR", Status = (int)ShipmentStatus.PickedUp, ShippedDate = DateTime.UtcNow.AddDays(-1), EstimatedDelivery = DateTime.UtcNow.AddDays(3), RecipientName = "Eva Martinez", Description = "Medical Supplies", WeightKg = 1.8 }
         );
         db.SaveChanges();
     }
 }

 // Configure the HTTP request pipeline.
 if (app.Environment.IsDevelopment())
 {
     app.UseWebAssemblyDebugging();
     app.UseMigrationsEndPoint();
 }
 else
 {
     app.UseExceptionHandler("/Error", createScopeForErrors: true);
     // The default HSTS value is 30 days. You may want to change this for production scenarios, see https://aka.ms/aspnetcore-hsts.
     app.UseHsts();
 }
 app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
 app.UseHttpsRedirection();

 app.UseAntiforgery();

 app.MapStaticAssets();
 app.MapRazorComponents<App>()
     .AddInteractiveServerRenderMode()
     .AddInteractiveWebAssemblyRenderMode()
     .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

 // Add additional endpoints required by the Identity /Account Razor components.
 app.MapAdditionalIdentityEndpoints();

 // Shipment API endpoints
 var shipmentApi = app.MapGroup("/api/shipments");

 shipmentApi.MapGet("/", async (string? status, string? search, IShipmentService service) =>
     Results.Ok(await service.GetShipmentsAsync(status, search)))
     .RequireAuthorization();

 shipmentApi.MapGet("/{id:int}", async (int id, IShipmentService service) =>
 {
     var shipment = await service.GetShipmentByIdAsync(id);
     return shipment is null ? Results.NotFound() : Results.Ok(shipment);
 }).RequireAuthorization();

 shipmentApi.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
 {
     var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
     return shipment is null ? Results.NotFound() : Results.Ok(shipment);
 });

 shipmentApi.MapPost("/", async (ShipmentDto dto, IShipmentService service) =>
 {
     var created = await service.CreateShipmentAsync(dto);
     return Results.Created($"/api/shipments/{created.Id}", created);
 }).RequireAuthorization();

 shipmentApi.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, IShipmentService service) =>
 {
     await service.UpdateShipmentStatusAsync(id, request.NewStatus);
     return Results.NoContent();
 }).RequireAuthorization();

 app.Run();

