 ﻿@page "/"

 <PageTitle>ShipmentTracker - Home</PageTitle>

 <div class="container">
     <div class="text-center py-5">
         <h1 class="display-4">Shipment Tracker</h1>
         <p class="lead text-muted">Track your shipments in real-time, anywhere in the world.</p>
     </div>

     <div class="row g-4 mb-5">
         <div class="col-md-6">
             <div class="card h-100 shadow-sm">
                 <div class="card-body text-center p-4">
                     <h3 class="bi bi-search mb-3"></h3>
                     <h5 class="card-title">Track a Shipment</h5>
                     <p class="card-text">Enter your tracking number to see real-time status and estimated delivery.</p>
                     <div class="input-group mb-3">
                         <input type="text" class="form-control" placeholder="Enter tracking number..."
                                @bind="trackingNumber" @bind:event="oninput"
                                @onkeydown="HandleTrackKeyDown" />
                         <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
                     </div>
                     @if (trackingError)
                     {
                         <div class="alert alert-warning mt-2">Please enter a tracking number.</div>
                     }
                 </div>
             </div>
         </div>

         <div class="col-md-6">
             <div class="card h-100 shadow-sm">
                 <div class="card-body text-center p-4">
                     <h3 class="bi bi-truck mb-3"></h3>
                     <h5 class="card-title">Dispatcher Dashboard</h5>
                     <p class="card-text">Manage all shipments, update statuses, and create new shipments.</p>
                     <AuthorizeView>
                         <Authorized>
                             <a href="dispatcher" class="btn btn-outline-primary">Go to Dashboard</a>
                         </Authorized>
                         <NotAuthorized>
                             <a href="Account/Login" class="btn btn-outline-primary">Login to Access</a>
                         </NotAuthorized>
                     </AuthorizeView>
                 </div>
             </div>
         </div>
     </div>
 </div>

 @code {
     [Inject] private NavigationManager Navigation { get; set; } = default!;

     private string trackingNumber = string.Empty;
     private bool trackingError;

     private void TrackShipment()
     {
         if (string.IsNullOrWhiteSpace(trackingNumber))
         {
             trackingError = true;
             return;
         }
         trackingError = false;
         Navigation.NavigateTo($"track/{Uri.EscapeDataString(trackingNumber.Trim())}");
     }

     private void HandleTrackKeyDown(KeyboardEventArgs e)
     {
         if (e.Key == "Enter") TrackShipment();
     }
 }

